async function run(params, api) {
  var maxLen = Math.min(params.max_length || 8000, 50000);
  api.log('Fetching: ' + params.url);
  var raw = await api.httpGet(params.url);
  var text = raw;
  if (text.length > maxLen) {
    text = text.slice(0, maxLen) + '\n... [truncated, total ' + raw.length + ' chars]';
  }
  return text;
}
